"use strict";parserFactory.register("hellping.org",()=>new HellpingParser);class HellpingParser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(e){let r=[...e.querySelectorAll("div.entry-content a")].filter(e=>""!==e.textContent.trim()),t=[...e.querySelectorAll("#primary-menu a")];return r.concat(t).map(e=>util.hyperLinkToChapter(e))}}